import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"股票回购","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/股票回购.md","filePath":"05_quotes/by-theme/股票回购.md"}'),r={name:"05_quotes/by-theme/股票回购.md"};function l(q,t,c,_,p,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="股票回购" tabindex="-1">股票回购 <a class="header-anchor" href="#股票回购" aria-label="Permalink to &quot;股票回购&quot;">​</a></h1><blockquote><p>&quot;回购股票只有在股价远低于内在价值时才有意义。这是对留下来的股东的负责行为。&quot;——巴菲特</p></blockquote><p>巴菲特是回购的最大支持者，但坚持只有在低估时才有意义。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;股票回购是向留在公司里的股东回报价值的方式。当股价远低于内在价值时，回购是最佳选择。&quot;</p></blockquote><blockquote><p>&quot;我们在2009年和2011年回购了大量伯克希尔股票，因为市场价格显著低于内在价值。这是资本配置的好决策。&quot;</p></blockquote><blockquote><p>&quot;有些人把回购当作管理层的工具，用来支撑股价。我们把回购当作股东价值的来源——只有低估时才动手。&quot;</p></blockquote><blockquote><p>&quot;分红和回购都是回报股东的方式。哪个更合适取决于股价相对于内在价值的位置。&quot;</p></blockquote><blockquote><p>&quot;当你用1美元回购价值2美元的股票时，你为每位股东创造了1美元的价值。这是最纯粹的资本配置行为。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1999年 · 2000年 · 2009年 · 2011年 · 2012年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
